		})
	}

	t.Run("non_transient_equal_revs", func(t *testing.T) {
		report := ExecuteBeadReport{
			Status:        ExecuteBeadStatusNoChanges,
			BaseRev:       "same",
			ResultRev:     "same",
			OutcomeReason: "triage_task_quality",
		}
		if !shouldSuppressNoProgress(report) {
			t.Fatalf("non-transient equal BaseRev/ResultRev should retain existing cooldown behavior")
		}
	})

	t.Run("non_transient_different_revs", func(t *testing.T) {
		report := ExecuteBeadReport{
			Status:        ExecuteBeadStatusNoChanges,
			BaseRev:       "base",
			ResultRev:     "result",
			OutcomeReason: "triage_task_quality",
		}
		if shouldSuppressNoProgress(report) {
			t.Fatalf("non-transient different BaseRev/ResultRev should retain existing non-cooldown behavior")
		}
	})

	t.Run("disrupted_still_short_circuits", func(t *testing.T) {
		report := ExecuteBeadReport{
			Status:    ExecuteBeadStatusExecutionFailed,
			BaseRev:   "same",
			ResultRev: "same",
			Disrupted: true,
		}
		if shouldSuppressNoProgress(report) {
			t.Fatalf("disrupted report should keep bypassing no-progress cooldown")
		}
	})
}

